 {"id":"bd-1nk","title":"Implement ClientInfoRenderer for connection display","description":"## Purpose and Rationale

Create a renderer that displays connected client information in a beautiful format. When clients connect or disconnect, operators should see clear, informative status updates.

## Background

MCP servers handle connections from various clients (Claude Desktop, VS Code extensions, custom clients). Displaying client information - name, version, capabilities - helps operators understand who is connected and what they can do.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/client/info.rs

use rich_rust::{Panel, Table, Column, Rule, JustifyMethod};
use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use fastmcp::protocol::{ClientInfo, Implementation};

/// Renders client information beautifully
pub struct ClientInfoRenderer {
    theme: FastMcpTheme,
    context: DisplayContext,
}

impl ClientInfoRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self { theme, context }
    }

    /// Render client connection notification
    pub fn render_connected(&self, client: &ClientInfo, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_connected_plain(client, console);
            return;
        }

        let icon = "🔗";
        let client_name = client.name.as_deref().unwrap_or("Unknown Client");
        let version = client.version.as_deref().unwrap_or("?");

        // Connection notification
        console.print(&format!(
            "\n{} [bold green]Client Connected[/]: [cyan]{}[/] [dim]v{}[/]",
            icon, client_name, version
        ));

        // Capabilities panel (if any)
        if self.has_capabilities(client) {
            self.render_capabilities(client, console);
        }
    }

    /// Render client disconnection notification
    pub fn render_disconnected(&self, client: &ClientInfo, reason: Option<&str>, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_disconnected_plain(client, reason, console);
            return;
        }

        let client_name = client.name.as_deref().unwrap_or("Unknown Client");

        let msg = if let Some(r) = reason {
            format!(
                "🔌 [yellow]Client Disconnected[/]: [cyan]{}[/] [dim]({})[/]",
                client_name, r
            )
        } else {
            format!("🔌 [yellow]Client Disconnected[/]: [cyan]{}[/]", client_name)
        };

        console.print(&msg);
    }

    /// Render detailed client info panel
    pub fn render_detail(&self, client: &ClientInfo, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_detail_plain(client, console);
            return;
        }

        let mut table = Table::new()
            .title("Connected Client")
            .with_column(Column::new("Property").style(self.theme.dim_style()))
            .with_column(Column::new("Value"));

        table.add_row_cells(["Name", client.name.as_deref().unwrap_or("Unknown")]);
        table.add_row_cells(["Version", client.version.as_deref().unwrap_or("Unknown")]);

        if let Some(impl_info) = &client.implementation {
            table.add_row_cells(["Implementation", &impl_info.name]);
            if let Some(v) = &impl_info.version {
                table.add_row_cells(["Impl Version", v]);
            }
        }

        // Capabilities
        if let Some(caps) = &client.capabilities {
            let caps_str = self.format_capabilities_short(caps);
            table.add_row_cells(["Capabilities", &caps_str]);
        }

        console.print_renderable(&table);
    }

    fn render_capabilities(&self, client: &ClientInfo, console: &FastMcpConsole) {
        if let Some(caps) = &client.capabilities {
            let mut items = Vec::new();

            if caps.roots.unwrap_or(false) {
                items.push("📁 Roots");
            }
            if caps.sampling.unwrap_or(false) {
                items.push("🎲 Sampling");
            }
            if caps.experimental.is_some() {
                items.push("🧪 Experimental");
            }

            if !items.is_empty() {
                console.print(&format!("  [dim]Capabilities: {}[/]", items.join(", ")));
            }
        }
    }

    fn format_capabilities_short(&self, caps: &ClientCapabilities) -> String {
        let mut items = Vec::new();
        if caps.roots.unwrap_or(false) { items.push("roots"); }
        if caps.sampling.unwrap_or(false) { items.push("sampling"); }
        if caps.experimental.is_some() { items.push("experimental"); }

        if items.is_empty() {
            "none".to_string()
        } else {
            items.join(", ")
        }
    }

    fn has_capabilities(&self, client: &ClientInfo) -> bool {
        client.capabilities.as_ref().map(|c| {
            c.roots.unwrap_or(false) || 
            c.sampling.unwrap_or(false) || 
            c.experimental.is_some()
        }).unwrap_or(false)
    }

    fn render_connected_plain(&self, client: &ClientInfo, console: &FastMcpConsole) {
        let name = client.name.as_deref().unwrap_or("Unknown");
        let version = client.version.as_deref().unwrap_or("?");
        console.print(&format!("Client Connected: {} v{}", name, version));
    }

    fn render_disconnected_plain(&self, client: &ClientInfo, reason: Option<&str>, console: &FastMcpConsole) {
        let name = client.name.as_deref().unwrap_or("Unknown");
        if let Some(r) = reason {
            console.print(&format!("Client Disconnected: {} ({})", name, r));
        } else {
            console.print(&format!("Client Disconnected: {}", name));
        }
    }

    fn render_detail_plain(&self, client: &ClientInfo, console: &FastMcpConsole) {
        console.print("Connected Client:");
        console.print(&format!("  Name: {}", client.name.as_deref().unwrap_or("Unknown")));
        console.print(&format!("  Version: {}", client.version.as_deref().unwrap_or("Unknown")));
    }
}
